   272→        VALUES ($1, $2, $3, $4, $5, $6, $7, $8)
   273→        ON CONFLICT (user_id) DO UPDATE SET
   274→          headline = COALESCE($2, candidate_profiles.headline),
   275→          bio = COALESCE($3, candidate_profiles.bio),
   276→          location = COALESCE($4, candidate_profiles.location),
   277→          linkedin_url = COALESCE($5, candidate_profiles.linkedin_url),
   278→          github_url = COALESCE($6, candidate_profiles.github_url),
   279→          portfolio_url = COALESCE($7, candidate_profiles.portfolio_url),
