   288→        parsed_data.contact.github,
   289→        parsed_data.contact.portfolio,
   290→        parsed_data.years_experience
   291→      ]);
   292→
   293→      // Update user name if found
   294→      if (parsed_data.contact.name) {
   295→        await pool.query('UPDATE users SET name = $1 WHERE id = $2 AND (name IS NULL OR name = \'\')',
   296→          [parsed_data.contact.name, req.user.id]);
