   309→          exp.company,
   310→          exp.title,
   311→          exp.location,
   312→          exp.start_date ? new Date(exp.start_date + '-01') : null,
   313→          exp.end_date && exp.end_date !== 'Present' ? new Date(exp.end_date + '-01') : null,
   314→          exp.is_current || exp.end_date === 'Present',
   315→          exp.description,
   316→          JSON.stringify(exp.achievements || []),
   317→          JSON.stringify(exp.skills_used || []),
   318→          i
   319→        ]);
   320→      }
   321→    }
   322→
   323→    // Apply education
   324→    if (sections.includes('education') && parsed_data.education) {
   325→      for (let i = 0; i < parsed_data.education.length; i++) {
   326→        const edu = parsed_data.education[i];
   327→        await pool.query(`
   328→          INSERT INTO education (user_id, institution, degree, field_of_study, start_date, end_date, gpa, achievements, order_index)
   329→          VALUES ($1, $2, $3, $4, $5, $6, $7, $8, $9)
   330→        `, [
   331→          req.user.id,
   332→          edu.institution,
   333→          edu.degree,
   334→          edu.field,
   335→          edu.start_date ? new Date(edu.start_date + '-01-01') : null,
   336→          edu.end_date && edu.end_date !== 'Present' ? new Date(edu.end_date + '-01-01') : null,
   337→          edu.gpa,
   338→          JSON.stringify(edu.achievements || []),
   339→          i
   340→        ]);
   341→      }
   342→    }
   343→
   344→    // Apply skills
   345→    if (sections.includes('skills') && parsed_data.skills) {
   346→      for (const skill of parsed_data.skills) {
   347→        await pool.query(`
   348→          INSERT INTO candidate_skills (user_id, skill_name, category, level)
