   432→    // Make Offer functionality
   433→    let currentOfferData = null;
   434→
   435→    function makeOffer(appId, candidateId, candidateName, candidateEmail, jobId, jobTitle) {
   436→      currentOfferData = { appId, candidateId, candidateName, candidateEmail, jobId, jobTitle };
   437→
   438→      // Pre-fill the modal
   439→      document.getElementById('offer-candidate-name').textContent = candidateName;
   440→      document.getElementById('offer-job-title').value = jobTitle;
   441→
   442→      // Set default start date to 2 weeks from now
   443→      const startDate = new Date();
   444→      startDate.setDate(startDate.getDate() + 14);
   445→      document.getElementById('offer-start-date').value = startDate.toISOString().split('T')[0];
   446→
   447→      // Show modal
   448→      document.getElementById('offer-modal').style.display = 'flex';
   449→    }
   450→
   451→    function closeOfferModal() {
   452→      document.getElementById('offer-modal').style.display = 'none';
   453→      document.getElementById('offer-form').reset();
   454→      currentOfferData = null;
   455→    }
   456→
   457→    async function submitOffer(e) {
   458→      e.preventDefault();
   459→
   460→      if (!currentOfferData) return;
   461→
   462→      const offerData = {
   463→        candidate_id: currentOfferData.candidateId,
   464→        job_id: currentOfferData.jobId,
   465→        title: document.getElementById('offer-job-title').value,
   466→        salary: parseFloat(document.getElementById('offer-salary').value),
   467→        start_date: document.getElementById('offer-start-date').value,
   468→        benefits: document.getElementById('offer-benefits').value
   469→      };
   470→
   471→      try {
   472→        // Create the offer
   473→        const createResult = await apiCall('/onboarding/offers', {
   474→          method: 'POST',
   475→          body: JSON.stringify(offerData)
   476→        });
   477→
   478→        if (!createResult || createResult.error) {
   479→          throw new Error(createResult?.error || 'Failed to create offer');
   480→        }
   481→
   482→        // Send the offer immediately
   483→        const sendResult = await apiCall(`/onboarding/offers/${createResult.id}/send`, {
   484→          method: 'POST'
   485→        });
   486→
   487→        // Update application status
   488→        await apiCall(`/recruiter/applications/${currentOfferData.appId}/status`, {
   489→          method: 'PUT',
   490→          body: JSON.stringify({ status: 'offered' })
   491→        });
   492→
   493→        alert('Offer sent successfully to ' + currentOfferData.candidateName + '!');
   494→        closeOfferModal();
   495→        loadApplications();
   496→      } catch (err) {
   497→        console.error('Error creating offer:', err);
   498→        alert('Failed to create offer: ' + err.message);
   499→      }
   500→    }
   501→  </script>
