   291→  <script>
   292→    // Load results
   293→    async function loadResults() {
   294→      await checkAuth();
   295→      setupUserMenu();
   296→
   297→      const urlParams = new URLSearchParams(window.location.search);
   298→      const sessionId = urlParams.get('session');
   299→      const assessmentId = urlParams.get('id');
   300→
   301→      if (!sessionId && !assessmentId) {
   302→        alert('No results found');
   303→        window.location.href = '/skill-assessments.html';
   304→        return;
   305→      }
   306→
   307→      try {
   308→        let result;
   309→
   310→        // Try dedicated session endpoint first (faster, more reliable)
   311→        if (sessionId) {
   312→          const sessionRes = await fetch(`/api/assessments/session/${sessionId}`, {
   313→            headers: { 'Authorization': `Bearer ${localStorage.getItem('rekrutai_token')}` }
   314→          });
   315→          if (sessionRes.ok) {
   316→            const sessionData = await sessionRes.json();
   317→            result = sessionData.result;
   318→          }
   319→        }
   320→
   321→        // Fallback: search through all results
   322→        if (!result) {
   323→          const response = await fetch('/api/assessments/results', {
   324→            headers: { 'Authorization': `Bearer ${localStorage.getItem('rekrutai_token')}` }
   325→          });
   326→
   327→          if (!response.ok) throw new Error('Failed to load results');
   328→
   329→          const data = await response.json();
   330→
   331→          if (assessmentId) {
   332→            result = data.results.find(r => r.id === parseInt(assessmentId));
   333→          } else if (sessionId) {
   334→            result = data.results.find(r => r.session_id === parseInt(sessionId));
   335→          }
   336→          if (!result) {
   337→            result = data.results[0]; // fallback to most recent
   338→          }
   339→        }
   340→
   341→        if (!result) {
   342→          throw new Error('Result not found');
   343→        }
   344→
   345→        displayResults(result);
   346→      } catch (error) {
   347→        console.error('Error loading results:', error);
   348→        document.getElementById('result-status').textContent = 'Error Loading Results';
   349→        document.getElementById('result-subtitle').textContent = 'Please try again';
   350→      }
   351→    }
   352→
   353→    // Display results
   354→    function displayResults(result) {
   355→      // Score animation
   356→      const score = result.score || 0;
   357→      const scoreCircle = document.getElementById('score-circle');
   358→      const circumference = 2 * Math.PI * 80;
   359→      const offset = circumference - (score / 100) * circumference;
   360→      
   361→      setTimeout(() => {
   362→        scoreCircle.style.strokeDashoffset = offset;
   363→      }, 100);
   364→
   365→      document.getElementById('score-value').textContent = score;
   366→
   367→      // Status
   368→      const passed = result.passed;
   369→      document.getElementById('result-status').textContent = passed ? 'Passed!' : 'Not Passed';
   370→      document.getElementById('result-subtitle').textContent = passed 
   371→        ? 'Great job! Your skill has been verified.'
   372→        : 'Keep practicing and try again.';
   373→
   374→      // Stats
   375→      const answersGiven = typeof result.answers_given === 'string'
   376→        ? JSON.parse(result.answers_given || '[]')
   377→        : (result.answers_given || []);
   378→      const correctCount = answersGiven.filter(a => a.isCorrect).length;
   379→      
   380→      document.getElementById('stat-correct').textContent = `${correctCount}/10`;
   381→      document.getElementById('stat-difficulty').textContent = `${result.max_difficulty_reached || 2}/5`;
   382→      
   383→      const duration = result.duration_seconds || 0;
   384→      const minutes = Math.floor(duration / 60);
   385→      const seconds = Math.floor(duration % 60);
   386→      document.getElementById('stat-time').textContent = `${minutes}m ${seconds}s`;
   387→
   388→      // Integrity
   389→      const integrityScore = result.anti_cheat_score || 100;
   390→      const integrityEl = document.getElementById('integrity-score');
   391→      integrityEl.textContent = integrityScore;
   392→      
   393→      integrityEl.className = 'integrity-score-value';
   394→      if (integrityScore >= 90) integrityEl.classList.add('excellent');
   395→      else if (integrityScore >= 70) integrityEl.classList.add('good');
   396→      else if (integrityScore >= 50) integrityEl.classList.add('fair');
   397→      else integrityEl.classList.add('poor');
   398→
   399→      document.getElementById('tab-switches').textContent = result.tab_switches || 0;
   400→      document.getElementById('copy-paste').textContent = result.copy_paste_attempts || 0;
   401→      document.getElementById('time-anomalies').textContent = result.time_anomalies || 0;
   402→
   403→      // Badge
   404→      if (passed) {
   405→        document.getElementById('badge-section').style.display = 'block';
   406→        document.getElementById('skill-name').textContent = result.skill_name || 'Skill';
   407→      }
   408→    }
   409→
   410→    // Initialize
   411→    document.addEventListener('DOMContentLoaded', loadResults);
   412→  </script>
