   485→      cleanResponse = cleanResponse.replace(/^```(?:json)?\s*/, '').replace(/\s*```$/, '');
   486→    }
   487→
   488→    const questionData = JSON.parse(cleanResponse);
   489→
   490→    // Validate the response
