   586→// Helper: Complete assessment
   587→async function completeAssessment(client, sessionId, userId) {
   588→  const sessionResult = await client.query(
   589→    'SELECT * FROM assessment_sessions WHERE id = $1',
   590→    [sessionId]
   591→  );
