   412→    async function submitAnswer() {
   413→      if (isCompleted) return;
   414→
   415→      // Get answer
   416→      if (currentQuestion.type === 'multiple_choice') {
   417→        if (!selectedAnswer) {
   418→          alert('Please select an answer');
   419→          return;
   420→        }
   421→      } else {
   422→        const textarea = document.getElementById('short-answer');
   423→        if (textarea) {
   424→          selectedAnswer = textarea.value.trim();
   425→        }
   426→        if (!selectedAnswer) {
   427→          alert('Please provide an answer');
   428→          return;
   429→        }
   430→      }
   431→
   432→      // Calculate time taken
   433→      const timeTaken = Math.floor((Date.now() - questionStartTime) / 1000);
   434→
   435→      // Stop timer
   436→      clearInterval(timerInterval);
   437→
   438→      // Disable submit button
   439→      const submitBtn = document.getElementById('submit-btn');
   440→      submitBtn.disabled = true;
   441→      submitBtn.textContent = 'Evaluating...';
   442→
   443→      // Submit to API
   444→      try {
   445→        const response = await fetch('/api/assessments/answer', {
   446→          method: 'POST',
   447→          headers: {
   448→            'Content-Type': 'application/json',
   449→            'Authorization': `Bearer ${localStorage.getItem('rekrutai_token')}`
   450→          },
   451→          body: JSON.stringify({
   452→            sessionId,
   453→            questionId: currentQuestion.id,
   454→            answer: selectedAnswer,
   455→            timeTaken
   456→          })
   457→        });
   458→
   459→        if (!response.ok) {
   460→          const errData = await response.json().catch(() => ({}));
   461→          throw new Error(errData.error || 'Failed to submit answer');
   462→        }
   463→
   464→        const data = await response.json();
   465→
   466→        // Show feedback
   467→        showFeedback(data);
   468→
   469→        // Store next question if not completed
   470→        if (!data.completed) {
   471→          currentQuestion = data.nextQuestion;
   472→        } else {
   473→          isCompleted = true;
   474→          // Change continue button text
   475→          document.getElementById('continue-btn').textContent = 'View Results';
   476→          document.getElementById('continue-btn').onclick = () => {
   477→            window.location.href = `/assessment-results.html?session=${sessionId}`;
   478→          };
   479→        }
   480→      } catch (error) {
   481→        console.error('Error submitting answer:', error);
   482→        alert('Failed to submit answer: ' + error.message);
   483→        submitBtn.disabled = false;
   484→        submitBtn.textContent = 'Submit Answer';
   485→      }
   486→    }
   487→
   488→    // Show feedback modal
   489→    function showFeedback(data) {
   490→      const modal = document.getElementById('feedback-modal');
   491→      const icon = document.getElementById('feedback-icon');
   492→      const title = document.getElementById('feedback-title');
   493→      const text = document.getElementById('feedback-text');
   494→
   495→      const isCorrect = data.feedback === 'Correct!';
   496→      icon.textContent = isCorrect ? '✅' : '❌';
   497→      title.textContent = data.feedback;
   498→      title.style.color = isCorrect ? 'var(--accent-primary)' : '#ef4444';
   499→
   500→      let feedbackHTML = '';
   501→      if (data.explanation) {
   502→        feedbackHTML += `<p style="margin-bottom: 12px;">${data.explanation}</p>`;
   503→      }
   504→      if (data.aiFeedback) {
   505→        feedbackHTML += `<p style="padding-top: 12px; border-top: 1px solid var(--border-color); font-style: italic;">${data.aiFeedback}</p>`;
   506→      }
   507→      if (data.completed) {
   508→        feedbackHTML += `<p style="margin-top: 16px; font-weight: 600; color: var(--accent-primary);">Assessment Complete! Final Score: ${data.score}</p>`;
   509→      }
   510→      text.innerHTML = feedbackHTML || 'Moving to next question...';
   511→
   512→      modal.classList.add('show');
   513→    }
   514→
   515→    // Next question
   516→    function nextQuestion() {
   517→      if (isCompleted) {
   518→        window.location.href = `/assessment-results.html?session=${sessionId}`;
   519→        return;
   520→      }
   521→
   522→      document.getElementById('feedback-modal').classList.remove('show');
   523→
   524→      // Re-enable submit button
   525→      const submitBtn = document.getElementById('submit-btn');
   526→      submitBtn.disabled = false;
   527→      submitBtn.textContent = 'Submit Answer';
   528→
   529→      displayQuestion();
   530→      timeRemaining = currentQuestion.timeLimit || 120;
   531→      startTimer(currentQuestion.timeLimit || 120);
   532→    }
   533→
   534→    // Timer
   535→    function startTimer(seconds) {
   536→      timeRemaining = seconds;
   537→      updateTimerDisplay();
   538→
   539→      timerInterval = setInterval(() => {
   540→        timeRemaining--;
   541→        updateTimerDisplay();
   542→
   543→        if (timeRemaining <= 0) {
   544→          clearInterval(timerInterval);
   545→          submitAnswer();
   546→        }
   547→      }, 1000);
   548→    }
   549→
   550→    function updateTimerDisplay() {
   551→      const minutes = Math.floor(timeRemaining / 60);
   552→      const seconds = timeRemaining % 60;
   553→      const display = `${minutes}:${seconds.toString().padStart(2, '0')}`;
   554→
   555→      const timerEl = document.getElementById('timer');
   556→      timerEl.textContent = display;
   557→
   558→      timerEl.className = 'timer';
   559→      if (timeRemaining <= 10) {
   560→        timerEl.classList.add('danger');
   561→      } else if (timeRemaining <= 30) {
   562→        timerEl.classList.add('warning');
   563→      }
   564→    }
   565→
   566→    // Anti-cheat: Tab visibility
   567→    document.addEventListener('visibilitychange', () => {
   568→      if (document.hidden && sessionId) {
   569→        isTabActive = false;
   570→        tabSwitchCount++;
   571→        logEvent('tab_switch', { count: tabSwitchCount });
   572→
   573→        const warning = document.getElementById('proctoring-warning');
   574→        warning.classList.add('show');
   575→        setTimeout(() => warning.classList.remove('show'), 3000);
   576→      } else {
   577→        isTabActive = true;
   578→      }
   579→    });
   580→
   581→    // Anti-cheat: Copy/paste detection
   582→    function logCopyPaste(event) {
   583→      copyPasteCount++;
   584→      logEvent('copy_paste', { count: copyPasteCount });
   585→    }
   586→
   587→    // Log anti-cheat event
   588→    async function logEvent(eventType, eventData) {
   589→      if (!sessionId) return;
   590→      try {
   591→        await fetch('/api/assessments/event', {
   592→          method: 'POST',
   593→          headers: {
   594→            'Content-Type': 'application/json',
   595→            'Authorization': `Bearer ${localStorage.getItem('rekrutai_token')}`
   596→          },
   597→          body: JSON.stringify({ sessionId, eventType, eventData })
   598→        });
   599→      } catch (error) {
   600→        console.error('Failed to log event:', error);
   601→      }
   602→    }
   603→
   604→    // Prevent right-click (basic anti-cheat)
   605→    document.addEventListener('contextmenu', e => e.preventDefault());
   606→
   607→    // Initialize on load
   608→    document.addEventListener('DOMContentLoaded', initAssessment);
   609→  </script>
   610→</body>
   611→</html>
